template <typename RealT>
void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            RealT dx = (RealT)(x - radius + 1);
            RealT dy = (RealT)(y - radius + 1);
            RealT distance = (RealT)sqrt((double)(dx * dx + dy * dy));
            if ((RealT)radius > distance)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

template <typename PixelT, typename RealT>
void dilate_matrix(PixelT *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (0 > startX) startX++;
    int startY = posY - error;
    while (0 > startY) startY++;
    int endX = posX + error;
    while (dimX < endX) endX--;
    int endY = posY + error;
    while (dimY < endY) endY--;

    for (int x = startX; x < endX; x++) {
        for (int y = startY; y < endY; y++) {
            RealT dx = (RealT)(x - posX);
            RealT dy = (RealT)(y - posY);
            RealT distance = (RealT)sqrt((double)(dx * dx + dy * dy));
            if ((RealT)error > distance)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = (PixelT)1;
        }
    }
}

template <typename PixelT, typename RealT>
void imdilate_disk(PixelT *matrix, int dimX, int dimY, int dimZ, int error, PixelT *newMatrix) {
    for (int z = 0; z < dimZ; z++) {
        for (int x = 0; x < dimX; x++) {
            for (int y = 0; y < dimY; y++) {
                if ((int)matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix<PixelT, RealT>(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

